DO $$
DECLARE
  row_slug text;
  cand_id uuid;
  current_pl_count int;
  current_lme_count int;
  target_count int;
  coverage_count int;
BEGIN
  FOR row_slug IN SELECT DISTINCT slug FROM _seed_legislacao_p0a2_lote_d LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = row_slug AND publicavel = true;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: pre-condicao pulada porque candidato publico nao existe neste banco local/CI minimo', row_slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO current_pl_count FROM projetos_lei WHERE candidato_id = cand_id;
    SELECT count(*) INTO current_lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
    SELECT count(*) INTO target_count FROM _seed_legislacao_p0a2_lote_d WHERE slug = row_slug;
    SELECT count(*) INTO coverage_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = 'legislacao-p0a2-lote-d-projetos-lei-residuais-20260508';

    IF current_pl_count NOT IN (0, target_count) THEN
      RAISE EXCEPTION 'Pre-condicao %: projetos_lei esperado 0 ou alvo idempotente %, encontrado %', row_slug, target_count, current_pl_count;
    END IF;

    IF current_pl_count = target_count AND coverage_count <> target_count THEN
      RAISE EXCEPTION 'Pre-condicao %: % rows existentes em projetos_lei mas apenas % com coverage_id alvo', row_slug, target_count, coverage_count;
    END IF;

    IF current_lme_count <> 0 THEN
      RAISE EXCEPTION 'Pre-condicao %: legislacao_mandato_executivo esperado 0, encontrado %', row_slug, current_lme_count;
    END IF;
  END LOOP;
END $$;

WITH target AS (
  SELECT
    c.id AS candidato_id,
    seed.*
  FROM _seed_legislacao_p0a2_lote_d seed
  JOIN candidatos c ON c.slug = seed.slug
  WHERE c.publicavel = true
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  target.tipo,
  target.numero,
  target.ano,
  target.ementa,
  target.fonte,
  target.proposicao_id_api,
  target.url_inteiro_teor,
  target.coverage_id,
  target.coverage_scope,
  target.metadata
FROM target
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  row_slug text;
  cand_id uuid;
  target_count int;
  coverage_count int;
  wrong_lme_count int;
  total_count int;
  expected_count int;
BEGIN
  FOR row_slug IN SELECT DISTINCT slug FROM _seed_legislacao_p0a2_lote_d LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = row_slug AND publicavel = true;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: pos-condicao pulada porque candidato publico nao existe neste banco local/CI minimo', row_slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO target_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND proposicao_id_api IN ('ALAP-ELEGIS:29263', 'ALAP-ELEGIS:30718', 'ALAP-ELEGIS:30739', 'ALAP-ELEGIS:31103', 'ALAP-ELEGIS:31851', 'ALAP-ELEGIS:31852', 'ALAP-ELEGIS:32070', 'ALAP-ELEGIS:32219', 'ALAP-ELEGIS:32388', 'ALAP-ELEGIS:32550', 'ALAP-ELEGIS:33957', 'ALAP-ELEGIS:33958', 'ALAP-ELEGIS:33959', 'ALAP-ELEGIS:33979', 'ALAP-ELEGIS:35867', 'ALAP-ELEGIS:36502', 'ALAP-ELEGIS:36503', 'ALAP-ELEGIS:37097', 'ALAP-ELEGIS:37098', 'ALAP-ELEGIS:38117', 'ALAP-ELEGIS:38398', 'ALAP-ELEGIS:38796', 'ALAP-ELEGIS:38814', 'ALAP-ELEGIS:38815', 'ALAP-ELEGIS:39417', 'ALAP-ELEGIS:40040', 'ALAP-ELEGIS:40238', 'ALAP-ELEGIS:40387', 'ALAP-ELEGIS:40388', 'ALAP-ELEGIS:40389', 'ALAP-ELEGIS:40390', 'ALAP-ELEGIS:40607', 'ALAP-ELEGIS:40608', 'ALAP-ELEGIS:40609', 'ALAP-ELEGIS:40610', 'ALAP-ELEGIS:40820', 'ALAP-ELEGIS:45244', 'ALAP-ELEGIS:45838', 'ALAP-ELEGIS:45925', 'ALAP-ELEGIS:47829', 'ALAP-ELEGIS:48053', 'ALAP-ELEGIS:51079', 'ALAP-ELEGIS:53474', 'ALAP-ELEGIS:53531', 'ALAP-ELEGIS:54142', 'ALAP-ELEGIS:54315', 'ALAP-ELEGIS:54485', 'ALAP-ELEGIS:54486', 'ALAP-ELEGIS:54487', 'ALAP-ELEGIS:54549', 'ALAP-ELEGIS:54550', 'ALAP-ELEGIS:54595', 'ALAP-ELEGIS:54596', 'ALAP-ELEGIS:54597', 'ALAP-ELEGIS:54752', 'ALAP-ELEGIS:54753', 'ALAP-ELEGIS:54754', 'ALAP-ELEGIS:54755', 'ALAP-ELEGIS:54756', 'ALAP-ELEGIS:54883', 'ALAP-ELEGIS:54884', 'ALAP-ELEGIS:54885', 'ALAP-ELEGIS:55240', 'ALAP-ELEGIS:55241', 'ALAP-ELEGIS:55242', 'ALAP-ELEGIS:55243', 'ALAP-ELEGIS:55748', 'ALAP-ELEGIS:55895', 'ALAP-ELEGIS:56763', 'ALAP-ELEGIS:57896', 'ALAP-ELEGIS:58868', 'ALAP-ELEGIS:60710', 'ALAP-ELEGIS:61742');

    SELECT count(*) INTO coverage_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = 'legislacao-p0a2-lote-d-projetos-lei-residuais-20260508'
      AND coverage_scope = 'inventario_ampliado_parcial_alap_dr_furlan_p0a2_lote_d_20260508';

    SELECT count(*) INTO wrong_lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    SELECT count(*) INTO total_count
    FROM projetos_lei
    WHERE candidato_id = cand_id;

    expected_count := CASE row_slug
      WHEN 'dr-furlan' THEN 73
      ELSE NULL
    END;

    IF expected_count IS NULL THEN
      RAISE EXCEPTION 'Pos-apply %: count esperado ausente na migration', row_slug;
    END IF;

    IF target_count <> expected_count THEN
      RAISE EXCEPTION 'Pos-apply %: esperadas % rows alvo em projetos_lei, encontradas %', row_slug, expected_count, target_count;
    END IF;

    IF target_count <> coverage_count THEN
      RAISE EXCEPTION 'Pos-apply %: target_count % difere de coverage_count %', row_slug, target_count, coverage_count;
    END IF;

    IF total_count <> target_count THEN
      RAISE EXCEPTION 'Pos-apply %: total projetos_lei esperado igual ao lote %, encontrado %', row_slug, target_count, total_count;
    END IF;

    IF wrong_lme_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply %: legislacao_mandato_executivo deveria permanecer 0, encontrado %', row_slug, wrong_lme_count;
    END IF;
  END LOOP;
END $$;
